	_pMinimumVentDistSpinnerSegment->SetRange(0.0f, 1000.0f, 10000.0f, 0);
	_pMinimumVentDistSpinnerSegment->SetFormat("%2gmm");
	_pMinimumVentDistSpinnerSegment->SetValue(0.0f);

	_pGroupingFrame = new CATDlgFrame(_pSegmentFrame, (const char*)"Grouping Frame", CATDlgGridLayout | CATDlgFraNoTitle);
	_pGroupingFrame->SetGridConstraints(3, 0, 5, 1, CATGRID_4SIDES);

	_pVentGroupingCheck = new CATDlgCheckButton(_pGroupingFrame, "Group Vents based on Segments");
	_pVentGroupingCheck->SetGridConstraints(0, 0, 5, 1, CATGRID_4SIDES);

