	_pLabelAcuteAngleMinimumDist = new CATDlgLabel(_pAcuteAngleMinDistFrame, (const char*)"Acute Angle Check Minimum Distance", 0 | CATDlgLabLeft);
	_pLabelAcuteAngleMinimumDist->SetGridConstraints(1, 0, 2, 1,CATGRID_4SIDES);

	_pAcuteAngleDistSpinner = new CATDlgSpinner(_pAcuteAngleMinDistFrame, (const char*)"AcuteAngle", CATDlgSpnEntry);
