void MRFVentAnalysisDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}

void MRFVentAnalysisDlg::ClearAllSelections()
{
	if (!!_pVentGeomSetSelector)
	{
		_pVentGeomSetSelector->ClearSelect();
	}
	if (!!_pSegmentGeomSetSelector)
	{
		_pSegmentGeomSetSelector->ClearSelect();
	}
	if (!!_pTireAssySelector)
	{
		_pTireAssySelector->ClearSelect();
	}
	if (!!_pReferenceSurfaceSelector)
	{
		_pReferenceSurfaceSelector->ClearSelect();
	}
}
void MRFVentAnalysisDlg::ShowVentAnalysisFrame(int index)
{
	if (0 == index)
	{
		_pSegmentFrame->SetVisibility(CATDlgShow);
		_pPitchFrame->SetVisibility(CATDlgHide);
	}
	else if (1 == index)
	{
		_pSegmentFrame->SetVisibility(CATDlgHide);
		_pPitchFrame->SetVisibility(CATDlgShow);
	}
}

void MRFVentAnalysisDlg::DisableOtherRadio(int iVentAnalysisType)
{
	CATDlgRadioButton * pSelectedRadio = NULL;
	if (0 == iVentAnalysisType)
	{
		pSelectedRadio = _pPitchRadio;
	}
	else if (1 == iVentAnalysisType)
	{
		pSelectedRadio = _pSegmentRadio;
	}

	if (NULL != pSelectedRadio && CATDlgDisable != pSelectedRadio->GetSensitivity())
	{
		pSelectedRadio->SetSensitivity(CATDlgDisable);
	}
}








